            print(f"      Sessions without skills: {without_skill} "
                  f"(failure rate: {without_rate:.0%})")
            print(f"      Marginal benefit: {delta:+.0%} "
                  f"({'skills reduce failures' if delta > 0.05 else 'no clear benefit' if abs(delta) < 0.05 else 'skills correlate with MORE failures — investigate'})")
